INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('42','BrowserScript.js_run','{"key":"BrowserScript.js_run","title":"JavaScript 실행","version":"1.0.5","src":"astronverse.browser.browser_script.BrowserScript().js_run","comment":"JavaScript 내용을 @{input_type} 방식으로 불러와 실행하고, 실행 결과를 @{program_script}에 저장합니다.","inputList":[{"types":"Browser","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"browser_obj","title":"브라우저 객체","name":"browser_obj","tip":"JavaScript를 실행할 브라우저 객체를 선택합니다.","value":[{"type":"str","value":""}],"required":true},{"types":"InputType","formType":{"type":"RADIO"},"key":"input_type","title":"입력 방식","name":"input_type","tip":"스크립트를 직접 입력할지 파일에서 읽을지 선택합니다.","options":[{"label":"직접 입력","value":"content"},{"label":"파일에서 읽기","value":"file"}],"default":"content","required":true},{"types":"Str","formType":{"type":"INPUT_PYTHON_TEXTAREAMODAL_VARIABLE"},"key":"content","title":"스크립트 내용","name":"content","tip":"실행할 JavaScript 코드를 입력합니다.","default":"","dynamics":[{"key":"$this.content.show","expression":"return $this.input_type.value == ''content''"}],"required":true},{"types":"PATH","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"file_type":"file","filters":[".js"]}},"key":"file_path","title":"스크립트 파일","name":"file_path","tip":"실행할 JavaScript 파일 경로를 선택합니다.","default":"","dynamics":[{"key":"$this.file_path.show","expression":"return $this.input_type.value == ''file''"}],"required":true},{"types":"List","formType":{"type":"SCRIPTPARAMS"},"key":"params","title":"매개변수","name":"params","tip":"스크립트에 전달할 매개변수를 순서대로 입력합니다.","need_parse":"json_str","required":false},{"types":"WebPick","formType":{"type":"PICK","params":{"use":"WebPick"}},"key":"element_data","title":"iframe 요소","name":"element_data","tip":"특정 iframe 안에서 실행할 때 iframe 요소를 선택합니다.","required":false,"noInput":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"iframe_url","title":"iframe 주소","name":"iframe_url","tip":"특정 ifr