INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('92','CV.cv_click','{"key":"CV.cv_click","title":"이미지 클릭","version":"1.0.1","src":"astronverse.vision.cv.CV().cv_click","comment":"이미지 @{input_data}의 @{click_position} 위치를 @{btn_type}/@{btn_model} 방식으로 클릭합니다.","inputList":[{"types":"IMGPick","formType":{"type":"PICK","params":{"use":"CV"}},"key":"input_data","title":"이미지","name":"input_data","tip":"이미지 라이브러리에서 선택하거나 화면에서 이미지를 선택합니다.","required":true,"noInput":true},{"types":"BtnType","formType":{"type":"RADIO"},"key":"btn_type","title":"마우스","name":"btn_type","tip":"","options":[{"label":"왼쪽 버튼","value":"left"},{"label":"가운데 버튼","value":"middle"},{"label":"오른쪽 버튼","value":"right"}],"default":"left","required":false},{"types":"BtnModel","formType":{"type":"RADIO"},"key":"btn_model","title":"클릭방식","name":"btn_model","tip":"","options":[{"label":"클릭","value":"click"},{"label":"더블클릭","value":"double_click"}],"default":"click","required":false},{"types":"PositionType","formType":{"type":"RADIO"},"key":"click_position","title":"클릭 위치","name":"click_position","tip":"마우스를 클릭할 이미지 내 위치를 선택합니다.","options":[{"label":"가운데 버튼","value":"center"},{"label":"임의 위치","value":"random"},{"label":"위치 지정","value":"specific"}],"default":"center","required":false},{"types":"Any","formType":{"type":"GRID"},"key":"specified_position","title":"위치 지정","name":"specified_position","tip":"","default":5,"dynamics":[{"key":"$this.specified_position.show","expression":"return $this.click_position.value == ''specific''"}],"required":false},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"horizontal_move","title":"가로 이동","name":"horizontal_move","tip":"","default":0,"value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.horizontal_move.show","expression":"return $this.click_position.value == ''specific''"}],"required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"vertical_move","title":"세로 이동","nam