INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('95','CV.is_image_exist','{"key":"CV.is_image_exist","title":"IF 이미지 존재","version":"1.0.1","src":"astronverse.vision.cv.CV().is_image_exist","comment":"현재 화면에서 이미지 @{input_data}의 존재 여부를 확인합니다.","inputList":[{"types":"IMGPick","formType":{"type":"PICK","params":{"use":"CV"}},"key":"input_data","title":"이미지","name":"input_data","tip":"이미지 라이브러리에서 선택하거나 화면에서 이미지를 선택합니다.","required":true,"noInput":true},{"types":"ExistType","formType":{"type":"RADIO"},"key":"exist_type","title":"파일명 충돌 처리 방식","name":"exist_type","tip":"이미지가 존재하는 경우와 찾을 수 없는 경우의 실행 흐름을 나눕니다.","options":[{"label":"존재함","value":"exist"},{"label":"찾을 수 없습니다","value":"not_exist"}],"default":"exist","required":false},{"types":"Float","formType":{"type":"SLIDER"},"key":"match_similarity","title":"매칭 정확도","name":"match_similarity","tip":"현재 화면에서 선택한 이미지와 일치하는 정도를 설정합니다. 값이 높을수록 더 엄격하게 매칭합니다.","default":0.95,"required":false},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"wait_time","title":"대기 시간(초)","name":"wait_time","tip":"지정한 시간이 지나면 대기를 중지합니다.","default":10,"value":[{"type":"str","value":""}],"level":"advanced","required":false}],"outputList":[],"icon":"if-image-exists","helpManual":"현재 창에서 지정한 이미지가 존재하는지 확인합니다."}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('96','CV.wait_image','{"key":"CV.wait_image","title":"이미지 대기","version":"1.0.1","src":"astronverse.vision.cv.CV().wait_image","comment":"이미지 대기(@{input_data})(@{wait_type})","inputList":[{"types":"IMGPick","formType":{"type":"PICK","params":{"use":"CV"}},"key":"input_data","title":"이미지","name":"input_data","tip":"이미지 라이브러리에서 선택하거나 화면에서 이미지를 선택합니다.","required":true,"noInput":true},{"types":"WaitType","formType":{"type":"RADIO"},"key":"wait_type","title":"대기 유형","name":"wait_type","tip":"이미지가 나타나거나 사라질 때까지 대기합니다.","options":[{"label":"이미지출력","value":"appear"},{"label":"이미지실패","value":"disappear"}],"default":"appear","required":false},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"wait_time","title":"대기 시간(초)","name":"wait_time","tip":"지정한 시간이 지나면 대기를 중지합니다.","default":10,"value":[{"type":"str","value":""}],"required":false},{"types":"Float","formType":{"type":"SLIDER"},"key":"match_similarity","title":"매칭 정확도","name":"match_similarity","tip":"현재 화면에서 선택한 이미지와 일치하는 정도를 설정합니다. 값이 높을수록 더 엄격하게 매칭합니다.","default":0.95,"required":false}],"outputList":[{"types":"Bool","formType":{"type":"RESULT"},"key":"image_wait_result","title":"대기 결과","tip":"대기 시간 안에 조건을 만족하면 true, 아니면 false를 반환합니다."}],"icon":"wait-image","helpManual":"이미지가 나타나거나 사라질 때까지 기다린 뒤 다음 흐름을 실행합니다."}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
