INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('100','DataProcess.set_variable_value','{"key":"DataProcess.set_variable_value","title":"변수값 설정","version":"1.0.2","src":"astronverse.dataprocess.data.DataProcess().set_variable_value","comment":"값 @{value} 변수 @{variable_var}","inputList":[{"types":"Any","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"value","title":"변수 값","name":"value","tip":"입력필요의변수 값","value":[{"type":"str","value":""}],"required":true},{"types":"VariableType","formType":{"type":"SELECT"},"key":"variable_type","title":"변수유형","name":"variable_type","tip":"선택할의변수유형","options":[{"label":"문자열","value":"str"},{"label":"정수","value":"int"},{"label":"데이터","value":"float"},{"label":"불리언 값 값","value":"bool"},{"label":"요소 객체 목록","value":"list"},{"label":"딕셔너리","value":"dict"},{"label":"JSON","value":"json"},{"label":"원그룹","value":"tuple"},{"label":null,"value":"other"}],"default":"int","required":true}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"variable_var","title":"후의변수 값","tip":"","dynamics":[{"key":"$this.variable_var.types","expression":"return [''int'',''str'', ''float'', ''bool'', ''list'', ''dict''].includes($this.variable_type.value) ? $this.variable_type.value[0].toUpperCase() + $this.variable_type.value.slice(1) : ''Any''"}]}],"icon":"set-variable-value","helpManual":""}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('101','Dialog.custom_box','{"key":"Dialog.custom_box","title":"사용자 지정 대화상자","version":"1.0.2","src":"astronverse.dialog.dialog.Dialog().custom_box","comment":"원하는 입력 항목과 버튼으로 구성한 대화상자를 표시하고 사용자의 선택 결과를 반환합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT"},"key":"box_title","title":"대화상자 제목","name":"box_title","tip":"대화상자 상단에 표시할 제목을 입력합니다.","default":"사용자 지정 대화상자","required":true,"limitLength":[-1,50]},{"types":"Str","formType":{"type":"MODALBUTTON"},"key":"design_interface","title":"대화상자 구성","name":"design_interface","tip":"버튼을 눌러 대화상자의 입력 항목과 레이아웃을 구성합니다.","need_parse":"json_str","required":false},{"types":"Bool","formType":{"type":"SWITCH"},"key":"auto_check","title":"자동으로 대화상자 닫기","name":"auto_check","tip":"제한 시간이 지나면 기본 버튼으로 자동 처리할지 선택합니다.","options":[{"label":"예","value":true},{"label":"아니오","value":false}],"default":false,"level":"advanced","required":false},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"wait_time","title":"대기 시간(초)","name":"wait_time","tip":"자동 닫기를 사용할 때 기다릴 시간을 초 단위로 입력합니다.","default":60,"value":[{"type":"str","value":""}],"level":"advanced","dynamics":[{"key":"$this.wait_time.show","expression":"return $this.auto_check.value == true"}],"required":false},{"types":"DefaultButtonCN","formType":{"type":"SELECT"},"key":"default_button","title":"시간 초과 시 선택할 버튼","name":"default_button","tip":"제한 시간이 지나면 자동으로 선택할 버튼을 지정합니다.","options":[{"label":"확인","value":"confirm"},{"label":"취소","value":"cancel"}],"default":"confirm","level":"advanced","dynamics":[{"key":"$this.default_button.show","expression":"return $this.auto_check.value == true"}],"required":true}],"outputList":[{"types":"DialogResult","formType":{"type":"RESULT"},"key":"dialog_result","title":"대화상자 결과","tip":"사용자가 입력한 값과 클릭한 버튼 결과를 저장합니다."}],"icon":"custom-dialog","helpManual":"사용자 지정 대화상자를 열고, 사용자가 입력하거나 선택한 결과를 변수로 저장합니다."}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('102','Dialog.input_box','{"key":"Dialog.input_box","title":"입력 대화상자","version":"1.0.2","src":"astronverse.dialog.dialog.Dialog().input_box","comment":"사용자에게 텍스트 또는 비밀번호 입력 대화상자를 표시하고 입력값을 반환합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT"},"key":"box_title","title":"대화상자 제목","name":"box_title","tip":"대화상자 상단에 표시할 제목을 입력합니다. 최대 50자입니다.","default":"입력 대화상자","required":false,"limitLength":[-1,50]},{"types":"InputType","formType":{"type":"RADIO"},"key":"input_type","title":"입력 방식","name":"input_type","tip":"텍스트 또는 비밀번호 입력 방식을 선택합니다.","options":[{"label":"텍스트","value":"text"},{"label":"비밀번호","value":"password"}],"default":"text","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"input_title","title":"입력 항목 제목","name":"input_title","tip":"입력란 위에 표시할 안내 제목을 입력합니다.","default":"입력 항목","value":[{"type":"str","value":""}],"required":false,"limitLength":[-1,60]},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"default_input_text","title":"기본 텍스트","name":"default_input_text","tip":"텍스트 입력란에 미리 표시할 기본값을 입력합니다. 최대 120자입니다.","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.default_input_text.show","expression":"return $this.input_type.value == ''text''"}],"required":false},{"types":"Str","formType":{"type":"DEFAULTPASSWORD"},"key":"default_input_pwd","title":"기본 비밀번호","name":"default_input_pwd","tip":"비밀번호 입력란에 미리 표시할 기본값을 입력합니다. 4자에서 16자까지 입력할 수 있습니다.","default":"","dynamics":[{"key":"$this.default_input_pwd.show","expression":"return $this.input_type.value == ''password''"}],"required":false,"limitLength":[4,16]},{"types":"Any","formType":{"type":"MODALBUTTON"},"key":"preview_button","title":"미리보기","name":"preview_button","tip":"대화상자를 미리 확인합니다.","required":false}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"input_content","title":"입력 내용","tip":"사용자가 입력한 내용을 저장합니다."}],