INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('103','Dialog.message_box','{"key":"Dialog.message_box","title":"메시지 대화상자","version":"1.0.2","src":"astronverse.dialog.dialog.Dialog().message_box","comment":"사용자에게 메시지, 경고, 질문, 오류 대화상자를 표시하고 선택한 버튼을 반환합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT"},"key":"box_title","title":"대화상자 제목","name":"box_title","tip":"대화상자 상단에 표시할 제목을 입력합니다. 최대 50자입니다.","default":"메시지 안내","required":false,"limitLength":[-1,50]},{"types":"MessageType","formType":{"type":"RADIO"},"key":"message_type","title":"메시지 유형","name":"message_type","tip":"정보, 경고, 질문, 오류 중 표시할 메시지 유형을 선택합니다.","options":[{"label":"정보","value":"message"},{"label":"경고","value":"warning"},{"label":"질문","value":"question"},{"label":"오류","value":"error"}],"default":"message","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"message_content","title":"메시지 내용","name":"message_content","tip":"대화상자에 표시할 내용을 입력합니다. 최대 120자입니다.","default":"","required":true,"limitLength":[-1,120]},{"types":"ButtonType","formType":{"type":"SELECT"},"key":"button_type","title":"버튼 구성","name":"button_type","tip":"사용자가 선택할 수 있는 버튼 구성을 선택합니다.","options":[{"label":"확인","value":"confirm"},{"label":"확인-취소","value":"confirm_cancel"},{"label":"예-아니오","value":"yes_no"},{"label":"예-아니오-취소","value":"yes_no_cancel"}],"default":"confirm","required":true},{"types":"Bool","formType":{"type":"SWITCH"},"key":"auto_check","title":"자동으로 대화상자 닫기","name":"auto_check","tip":"제한 시간이 지나면 기본 버튼으로 자동 처리할지 선택합니다.","options":[{"label":"예","value":true},{"label":"아니오","value":false}],"default":false,"level":"advanced","required":false},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"wait_time","title":"대기 시간(초)","name":"wait_time","tip":"자동 닫기를 사용할 때 기다릴 시간을 초 단위로 입력합니다.","default":60,"value":[{"type":"str","value":""}],"level":"advanced","dynamics":[{"key":"$this.wait_time.show","expression":"return $this.auto_check.value == true"}],"required":false},{"types":"DefaultButtonC","formType":{"type":"SELECT"},"key":"default_button_c","title":"시간 초과 시 선택할 버튼","name":"default_button_c","tip":"제한 시간이 지나면 자동으로 선택할 버튼을 지정합니다.","options":[{"label":"확인","value":"confirm"}],"default":"confirm","level":"advanced","dynamics":[{"key":"$this.default_button_c.show","expression":"return $this.auto_check.value == true && $this.button_type.value == ''confirm''"}],"required":true},{"types":"DefaultButtonCN","formType":{"type":"SELECT"},"key":"default_button_cn","title":"시간 초과 시 선택할 버튼","name":"default_button_cn","tip":"제한 시간이 지나면 자동으로 선택할 버튼을 지정합니다.","options":[{"label":"확인","value":"confirm"},{"label":"취소","value":"cancel"}],"default":"confirm","level":"advanced","dynamics":[{"key":"$this.default_button_cn.show","expression":"return $this.auto_check.value == true && $this.button_type.value == ''confirm_cancel''"}],"required":true},{"types":"DefaultButtonY","formType":{"type":"SELECT"},"key":"default_button_y","title":"시간 초과 시 선택할 버튼","name":"default_button_y","tip":"제한 시간이 지나면 자동으로 선택할 버튼을 지정합니다.","options":[{"label":"예","value":"yes"},{"label":"아니오","value":"no"}],"default":"yes","level":"advanced","dynamics":[{"key":"$this.default_button_y.show","expression":"return $this.auto_check.value == true && $this.button_type.value == ''yes_no''"}],"required":true},{"types":"DefaultButtonYN","formType":{"type":"SELECT"},"key":"default_button_yn","title":"시간 초과 시 선택할 버튼","name":"default_button_yn","tip":"제한 시간이 지나면 자동으로 선택할 버튼을 지정합니다.","options":[{"label":"예","value":"yes"},{"label":"아니오","value":"no"},{"label":"취소","value":"cancel"}],"default":"yes","level":"advanced","dynamics":[{"key":"$this.default_button_yn.show","expression":"return $this.auto_check.value == true && $this.button_type.value == ''yes_no_cancel''"}],"required":true},{"types":"Any","formType":{"type":"MODALBUTTON"},"key":"preview_button","title":"미리보기","name":"preview_button","tip":"대화상자를 미리 확인합니다.","required":false}],"outputList"