INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('116','Docx.close_docx','{"key":"Docx.close_docx","title":"Word 닫기","version":"1.0.2","src":"astronverse.word.docx.Docx().close_docx","comment":"Word 객체 @{doc}를 닫고 필요하면 저장합니다.","inputList":[{"types":"DocumentObject","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"doc","title":"Word 객체","name":"doc","tip":"닫을 Word 문서 객체를 선택합니다.","value":[{"type":"str","value":""}],"required":true},{"types":"CloseRangeType","formType":{"type":"RADIO"},"key":"close_range_flag","title":"닫을 범위","name":"close_range_flag","tip":"현재 문서만 닫을지 모든 문서를 닫을지 선택합니다.","options":[{"label":"현재 문서","value":"one"},{"label":"모든 문서","value":"all"}],"default":"one","required":true},{"types":"SaveType","formType":{"type":"RADIO"},"key":"save_type","title":"저장 방식","name":"save_type","tip":"저장, 다른 이름으로 저장, 저장 안 함 중 선택합니다.","options":[{"label":"저장","value":"save"},{"label":"다른 이름으로 저장","value":"save_as"},{"label":"저장 안 함","value":"abort"}],"default":"save","dynamics":[{"key":"$this.save_type.show","expression":"return $this.close_range_flag.value == ''one''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"file_path","title":"저장 폴더","name":"file_path","tip":"다른 이름으로 저장할 폴더를 선택합니다.","default":"","dynamics":[{"key":"$this.file_path.show","expression":"return $this.save_type.value == ''save_as'' && $this.close_range_flag.value == ''one''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"file_name","title":"파일 이름","name":"file_name","tip":"다른 이름으로 저장할 파일 이름을 입력합니다.","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.file_name.show","expression":"return $this.save_type.value == ''save_as'' && $this.close_range_flag.value == ''one''"}],"required":true},{"types":"FileExistenceType","formType":{"type":"RADIO"},"key":"exist_handle_type","title":"같은 이름이 있을 때","name":"exist_handle_type","tip":"기존 파일이 있을 때 처리 방식을 선택합니다.","options":[{"label":"기존 파일 덮어쓰기","value":"overwrite"},{"label":"사본 파일 생성","value":"rename"},{"label":"저장 건너뛰기","value":"cancel"}],"default":"rename","dynamics":[{"key":"$this.exist_handle_type.show","expression":"return $this.close_range_flag.value == ''one''"}],"required":true},{"types":"Bool","formType":{"type":"SWITCH","params":{}},"key":"pkill_flag","title":"프로그램 종료","name":"pkill_flag","tip":"모든 문서를 닫을 때 Word 또는 WPS 프로세스까지 종료할지 선택합니다.","options":[{"label":"예","value":true},{"label":"아니오","value":false}],"default":false,"dynamics":[{"key":"$this.pkill_flag.show","expression":"return $this.close_range_flag.value == ''all''"}],"required":true}],"outputList":[],"icon":"word-close-document","helpManual":""}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('117','Docx.convert_format','{"key":"Docx.convert_format","title":"Word를 PDF/TXT로 내보내기","version":"1.0.2","src":"astronverse.word.docx.Docx().convert_format","comment":"에서Word객체 @{doc} 중, 내보내기지정내용로PDF또는TXT파일","inputList":[{"types":"DocumentObject","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"doc","title":"Word객체","name":"doc","tip":"본프로그램전순서기존가능(예열기, 생성)반환의Word객체","value":[{"type":"str","value":""}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"output_path","title":"내보내기경로","name":"output_path","tip":"선택할내보내기의폴더","default":"","required":true},{"types":"Bool","formType":{"type":"SWITCH","params":{}},"key":"default_name","title":"여부사용이름","name":"default_name","tip":"선택여부사용이름","options":[{"label":"예","value":true},{"label":"아니오","value":false}],"default":true,"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"output_name","title":"내보내기파일이름","name":"output_name","tip":"입력아니오형식후의파일이름","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.output_name.show","expression":"return $this.default_name.value == false"}],"required":true},{"types":"FileType","formType":{"type":"RADIO"},"key":"output_file_type","title":"내보내기파일형식","name":"output_file_type","tip":"선택중내보내기로pdf예txt","options":[{"label":"PDF","value":"pdf"},{"label":"TXT","value":"txt"}],"default":"pdf","required":true},{"types":"ConvertPageType","formType":{"type":"SELECT"},"key":"page_type","title":"페이지","name":"page_type","tip":"선택할내보내기전체페이지, 지정페이지, 현재페이지, 현재선택중내용","options":[{"label":"전체페이지","value":0},{"label":"현재페이지","value":2},{"label":"지정페이지","value":3},{"label":"선택중내용","value":1}],"default":0,"dynamics":[{"key":"$this.page_type.show","expression":"return $this.output_file_type.value == ''pdf''"}],"required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key