INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('133','Docx.save_docx','{"key":"Docx.save_docx","title":"Word 저장","version":"1.0.2","src":"astronverse.word.docx.Docx().save_docx","comment":"Word 객체 @{doc}를 @{save_type} 방식으로 저장하고 저장 경로 @{save_file_path}를 반환합니다.","inputList":[{"types":"DocumentObject","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"doc","title":"Word 객체","name":"doc","tip":"저장할 Word 문서 객체를 선택합니다.","value":[{"type":"str","value":""}],"required":true},{"types":"SaveType","formType":{"type":"RADIO"},"key":"save_type","title":"저장 방식","name":"save_type","tip":"저장, 다른 이름으로 저장, 저장 안 함 중 선택합니다.","options":[{"label":"저장","value":"save"},{"label":"다른 이름으로 저장","value":"save_as"},{"label":"저장 안 함","value":"abort"}],"default":"save","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"file_path","title":"저장 폴더","name":"file_path","tip":"다른 이름으로 저장할 폴더를 선택합니다.","default":"","dynamics":[{"key":"$this.file_path.show","expression":"return $this.save_type.value == ''save_as''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"file_name","title":"파일 이름","name":"file_name","tip":"다른 이름으로 저장할 파일 이름을 입력합니다.","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.file_name.show","expression":"return $this.save_type.value == ''save_as''"}],"required":true},{"types":"FileExistenceType","formType":{"type":"RADIO"},"key":"exist_handle_type","title":"같은 이름이 있을 때","name":"exist_handle_type","tip":"기존 파일이 있을 때 처리 방식을 선택합니다.","options":[{"label":"기존 파일 덮어쓰기","value":"overwrite"},{"label":"사본 파일 생성","value":"rename"},{"label":"저장 건너뛰기","value":"cancel"}],"default":"rename","dynamics":[{"key":"$this.exist_handle_type.show","expression":"return $this.save_type.value == ''save_as''"}],"required":true},{"types":"Bool","formType":{"type":"SWITCH","params":{}},"key":"close_flag","title":"저장 후 닫기