INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('181','File.file_copy','{"key":"File.file_copy","title":"파일 복사","version":"1.0.1","src":"astronverse.system.file.File().file_copy","comment":"복사파일 @{file_path} 까지지정디렉터리 @{target_path} 아래, 저장복사후의파일 경로 @{copy_file_path}","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"file"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"선택또는입력대기복사파일 경로","default":"","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"target_path","title":"압축 해제 폴더","name":"target_path","tip":"선택또는입력목록 디렉터리","default":"","required":true},{"types":"StateType","formType":{"type":"RADIO"},"key":"state_type","title":"디렉터리가 없을 때","name":"state_type","tip":"지정한 디렉터리가 없을 때 실행할 동작","options":[{"label":"생성","value":"create"},{"label":"안내오류","value":"error"}],"default":"error","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON","params":{"size":"middle"}},"key":"file_name","title":"파일 이름","name":"file_name","tip":"지정복사후파일이름, 필요하지 않습니다입력파일이름, 비워 두면사용기존파일이름","default":"","required":false},{"types":"OptionType","formType":{"type":"SELECT"},"key":"copy_options","title":"파일존재함시","name":"copy_options","tip":"선택지정디렉터리아래파일완료존재함시의; 완료본:를에서파일이름후증가추가숫자식별자, 예a(1).txt, 결과가본파일존재함, 이면숫자증가; 덮어쓰기:삭제완료존재함파일다시 생성; 건너뛰기:반환현재완료존재함파일 경로","options":[{"label":"덮어쓰기","value":"overwrite"},{"label":"건너뛰기","value":"skip"},{"label":"생성본","value":"generate"}],"default":"generate","required":false}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"copy_file_path","title":"복사후파일 경로","tip":"출력복사후파일 경로, 저장변수, 데이터 유형: 문자열"}],"icon":"copy-file","helpManual":"복사목록파일까지지정디렉터리"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
