INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('186','File.file_move','{"key":"File.file_move","title":"파일 이동","version":"1.0.1","src":"astronverse.system.file.File().file_move","comment":"를파일 @{file_path} 지정디렉터리 @{target_folder} 아래, 저장후의파일 경로 @{move_file_path}","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"file"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"선택또는입력대기파일 경로","default":"","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"target_folder","title":"지정디렉터리","name":"target_folder","tip":"대상 디렉터리를 선택하거나 입력하세요. 지정한 디렉터리가 없으면 생성합니다.","default":"","required":true},{"types":"StateType","formType":{"type":"RADIO"},"key":"state_type","title":"디렉터리가 없을 때","name":"state_type","tip":"지정한 디렉터리가 없을 때 실행할 동작","options":[{"label":"생성","value":"create"},{"label":"안내오류","value":"error"}],"default":"error","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"file_name","title":"파일 이름","name":"file_name","tip":"입력후파일이름(아니오필요후이름), 비워 두면사용기존파일이름","default":"","required":false},{"types":"OptionType","formType":{"type":"SELECT"},"key":"exist_options","title":"파일존재함시","name":"exist_options","tip":"선택파일존재함시실행의(덮어쓰기, 건너뛰기, 완료본)","options":[{"label":"덮어쓰기","value":"overwrite"},{"label":"건너뛰기","value":"skip"},{"label":"생성본","value":"generate"}],"default":"generate","required":false}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"move_file_path","title":"후파일 경로","tip":"출력후파일 경로변수, 데이터 유형: 문자열"}],"icon":"move-file","helpManual":"를지정파일까지목록 디렉터리, 출력후의파일 경로변수"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('187','File.file_read','{"key":"File.file_read","title":"파일 읽기","version":"1.0.1","src":"astronverse.system.file.File().file_read","comment":"@{read_type} 방식으로 파일 @{file_path}의 내용을 읽고 변수 @{read_file_content}에 저장합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"file"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"읽을 파일 경로를 선택하거나 입력합니다. 지원 파일 유형: \".txt\",  \".docx\",  \".md\",  \".py\",  \".json\", \".csv\"","default":"","required":true},{"types":"ReadType","formType":{"type":"SELECT"},"key":"read_type","title":"읽기 방식","name":"read_type","tip":"전체 내용, 행 목록, 바이트 중 파일을 읽을 방식을 선택합니다.","options":[{"label":"전체","value":"all"},{"label":"요소 객체 목록","value":"list"},{"label":"이제어방식가져오기","value":"byte"}],"default":"all","required":false},{"types":"EncodeType","formType":{"type":"SELECT"},"key":"encode_type","title":"인코딩","name":"encode_type","tip":"파일을 읽을 때 사용할 문자 인코딩을 선택합니다. 기본값은 대상 파일의 인코딩을 자동으로 사용합니다.","options":[{"label":"","value":"default"},{"label":"ansi","value":"ansi"},{"label":"utf-8","value":"utf-8"},{"label":"utf-16","value":"utf-16"},{"label":"utf-16 be","value":"utf-16 be"},{"label":"gbk","value":"gbk"},{"label":"gb2312","value":"gb2312"},{"label":"gb18030","value":"gb18030"}],"default":"default","required":false}],"outputList":[{"types":"Any","formType":{"type":"RESULT"},"key":"read_file_content","title":"읽은 내용","tip":"읽은 파일 내용을 저장합니다."}],"icon":"read-file","helpManual":"지정한 파일의 내용을 읽어 변수에 저장합니다."}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('188','File.file_rename','{"key":"File.file_rename","title":"파일 이름 변경","version":"1.0.1","src":"astronverse.system.file.File().file_rename","comment":"를파일 @{file_path} 이름 변경로 @{new_name} 저장이름 변경후의파일 경로 @{rename_file_path}","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"file"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"선택또는입력대기이름 변경파일 경로","default":"","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"new_name","title":"새파일이름","name":"new_name","tip":"입력새파일이름(아니오필요후이름)","default":"","required":true},{"types":"OptionType","formType":{"type":"SELECT"},"key":"exist_options","title":"파일존재함시","name":"exist_options","tip":"선택파일존재함시실행의(덮어쓰기, 건너뛰기, 완료본)","options":[{"label":"덮어쓰기","value":"overwrite"},{"label":"건너뛰기","value":"skip"},{"label":"생성본","value":"generate"}],"default":"generate","required":false}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"rename_file_path","title":"이름 변경후파일 경로","tip":"출력이름 변경후파일 경로변수, 데이터 유형: 문자열"}],"icon":"rename-file","helpManual":"를지정파일이름 변경, 출력이름 변경후의파일 경로변수"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('189','File.file_search','{"key":"File.file_search","title":"파일 검색","version":"1.0.1","src":"astronverse.system.file.File().file_search","comment":"에서 @{folder_path} 디렉터리중조회파일이름패키지 @{search_pattern} 의파일, 저장매칭파일 경로변수 @{find_file_result}","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"folder_path","title":"대기조회파일에서디렉터리","name":"folder_path","tip":"선택또는입력대기조회파일에서디렉터리","default":"","required":true},{"types":"SearchType","formType":{"type":"RADIO"},"key":"find_type","title":"조회방식","name":"find_type","tip":"조회 방식을 지정하세요. 파일명 매칭, 파일명 분할 매칭, 정규식 테이블 방식 매칭을 지원합니다.","options":[{"label":"매칭","value":"exact"},{"label":"매칭","value":"fuzzy"},{"label":"정상이면테이블방식매칭","value":"regex"}],"default":"fuzzy","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"search_pattern","title":"조회파일이름","name":"search_pattern","tip":"입력조회내용","default":"","required":true},{"types":"TraverseType","formType":{"type":"RADIO"},"key":"traverse_subfolder","title":"폴더","name":"traverse_subfolder","tip":"선택여부폴더","options":[{"label":"포함","value":"yes"},{"label":"포함 안 함","value":"no"}],"default":"no","level":"advanced","required":false}],"outputList":[{"types":"List","formType":{"type":"RESULT"},"key":"find_file_result","title":"저장조회결과","tip":"출력매칭파일 경로목록, 저장까지변수, 데이터 유형: 목록"}],"icon":"find-file","helpManual":"에서지정디렉터리중조회파일이름패키지지정내용의파일, 출력파일목록변수"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('190','File.file_wait_status','{"key":"File.file_wait_status","title":"파일 상태 대기","version":"1.0.1","src":"astronverse.system.file.File().file_wait_status","comment":"파일 @{file_path}가 @{status_type} 상태가 될 때까지 기다리고 결과를 @{wait_file_result}에 저장합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"file"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"상태를 기다릴 파일 경로를 선택하거나 입력합니다.","default":"","required":true},{"types":"StatusType","formType":{"type":"RADIO"},"key":"status_type","title":"대기 상태","name":"status_type","tip":"파일 생성 또는 삭제 중 기다릴 상태를 선택합니다.","options":[{"label":"생성됨","value":"created"},{"label":"삭제됨","value":"deleted"}],"default":"created","required":false},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"wait_time","title":"제한 시간(초)","name":"wait_time","tip":"파일 상태를 기다릴 제한 시간을 초 단위로 입력합니다.","default":10,"value":[{"type":"str","value":""}],"required":false}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"wait_file_result","title":"대기 결과","tip":"지정한 상태가 되면 true, 제한 시간이 지나면 false를 반환합니다."}],"icon":"wait-file","helpManual":"대기파일상태로지정상태시실행다음 단계, 출력대기 결과변수"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('191','File.file_write','{"key":"File.file_write","title":"파일 쓰기","version":"1.0.1","src":"astronverse.system.file.File().file_write","comment":"내용을 파일에 쓰고 저장된 파일 경로를 반환합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"file"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"파일 경로를 선택하거나 입력하세요. 지원 파일 유형 - \".txt\", \".docx\", \".md\", \".py\", \".json\", \".csv\"","default":"","required":true},{"types":"StateType","formType":{"type":"RADIO"},"key":"file_option","title":"파일이 없을 때","name":"file_option","tip":"선택한 파일이 없을 때 실행할 동작","options":[{"label":"생성","value":"create"},{"label":"안내오류","value":"error"}],"default":"error","required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON","params":{"size":"middle"}},"key":"msg","title":"쓸 내용","name":"msg","tip":"파일에 쓸 내용을 입력합니다.","default":"","required":true},{"types":"WriteType","formType":{"type":"RADIO"},"key":"write_type","title":"쓰기 방식","name":"write_type","tip":"기존 내용을 덮어쓸지 끝에 이어 쓸지 선택합니다.","options":[{"label":"덮어쓰기","value":"overwrite"},{"label":"이어쓰기","value":"append"}],"default":"append","required":false},{"types":"EncodeType","formType":{"type":"SELECT"},"key":"encode_type","title":"인코딩","name":"encode_type","tip":"파일에 사용할 문자 인코딩을 선택합니다. 기본값은 대상 파일의 인코딩을 자동으로 사용합니다.","options":[{"label":"","value":"default"},{"label":"ansi","value":"ansi"},{"label":"utf-8","value":"utf-8"},{"label":"utf-16","value":"utf-16"},{"label":"utf-16 be","value":"utf-16 be"},{"label":"gbk","value":"gbk"},{"label":"gb2312","value":"gb2312"},{"label":"gb18030","value":"gb18030"}],"default":"default","required":false}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"write_file_path","title":"저장된 파일 경로","tip":"쓰기 완료 후 파일 경로를 저장합니다."}],"icon":"write-file","helpManual":"지정한 파일에 텍스트를 쓰고 파일 경로를 출력합니다."}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('192','File.get_file_encoding_type','{"key":"File.get_file_encoding_type","title":"파일 인코딩 가져오기","version":"1.0.1","src":"astronverse.system.file.File().get_file_encoding_type","comment":"파일 @{file_path}의 인코딩 유형을 가져와 @{file_encoding_type}에 저장합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"file"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"인코딩을 확인할 파일 경로를 선택하거나 입력합니다.","default":"","required":true}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"file_encoding_type","title":"파일 인코딩","tip":"감지한 파일 인코딩을 문자열로 반환합니다."}],"icon":"get-file-encoding","helpManual":"파일의 문자 인코딩을 감지해 출력 변수에 저장합니다."}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('193','File.get_file_list','{"key":"File.get_file_list","title":"파일 목록 가져오기","version":"1.0.1","src":"astronverse.system.file.File().get_file_list","comment":"지정한 폴더의 파일 목록을 가져와 목록 또는 Excel 파일로 저장합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"folder_path","title":"폴더 경로","name":"folder_path","tip":"파일 목록을 가져올 폴더를 선택하거나 입력합니다.","default":"","required":true},{"types":"TraverseType","formType":{"type":"RADIO"},"key":"traverse_subfolder","title":"하위 폴더 포함","name":"traverse_subfolder","tip":"하위 폴더 안의 파일까지 함께 가져올지 선택합니다.","options":[{"label":"포함","value":"yes"},{"label":"포함 안 함","value":"no"}],"default":"no","required":true},{"types":"Bool","formType":{"type":"SWITCH","params":{}},"key":"tempfile_include","title":"임시 파일 포함","name":"tempfile_include","tip":"~, ~$ 또는 .tmp 같은 임시 파일을 결과에 포함할지 선택합니다.","options":[{"label":"예","value":true},{"label":"아니오","value":false}],"default":true,"required":true},{"types":"OutputType","formType":{"type":"RADIO"},"key":"output_type","title":"출력 방식","name":"output_type","tip":"결과를 목록으로 반환할지 Excel 파일로 저장할지 선택합니다.","options":[{"label":"요소 객체 목록","value":"list"},{"label":"Excel 파일로 저장","value":"excel"}],"default":"list","required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"excel_path","title":"Excel 저장 폴더","name":"excel_path","tip":"Excel 파일을 저장할 폴더를 선택하거나 입력합니다.","default":"","dynamics":[{"key":"$this.excel_path.show","expression":"return $this.output_type.value == ''excel''"}],"required":true},{"types":"StateType","formType":{"type":"RADIO"},"key":"state_type","title":"디렉터리가 없을 때","name":"state_type","tip":"선택한 Excel 저장 디렉터리가 없을 때 실행할 동작","options":[{"label":"생성","value":"create"},{"label":"안내오류","value":"error"}],"default":"error","dynamics":[{"key":"$this.state_type.show