INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('234','Network.ftp_delete','{"key":"Network.ftp_delete","title":"파일/폴더 삭제(FTP)","version":"1.0.1","src":"astronverse.network.ftp.FTP().ftp_delete","comment":"삭제(@{ftp_instance})위(@{delete_file_name||delete_folder_name}),출력삭제결과변수(@{delete_ftp_result})","inputList":[{"types":"Any","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"ftp_instance","title":"FTP연결객체","name":"ftp_instance","tip":"실행파일/폴더삭제의FTP연결객체","value":[{"type":"str","value":""}],"required":true},{"types":"FileType","formType":{"type":"RADIO"},"key":"file_type","title":"삭제객체","name":"file_type","tip":"","options":[{"label":"파일","value":"file"},{"label":"폴더","value":"folder"}],"default":"file","required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"delete_file_name","title":"대기삭제파일","name":"delete_file_name","tip":"지원단일개또는다중개파일삭제,다중개파일이름사용열기,예:test1.txt,test2.txt,test3.txt","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.delete_file_name.show","expression":"return $this.file_type.value == ''file''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"delete_folder_name","title":"대기삭제폴더","name":"delete_folder_name","tip":"지원단일개또는다중개폴더삭제,다중개폴더사용열기,예:folder1,folder2,folder3","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.delete_folder_name.show","expression":"return $this.file_type.value == ''folder''"}],"required":true}],"outputList":[{"types":"Bool","formType":{"type":"RESULT"},"key":"delete_ftp_result","title":"삭제결과","tip":"출력삭제결과까지변수,데이터 유형: 불리언 값"}],"icon":"delete-folder-ftp","helpManual":"삭제FTP서비스서버중지정파일/폴더"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('235','Network.ftp_download','{"key":"Network.ftp_download","title":"파일/폴더 다운로드(FTP)","version":"1.0.1","src":"astronverse.network.ftp.FTP().ftp_download","comment":"다운로드(@{download_file_name||download_folder_name})본디렉터리(@{dst_path}),를다운로드후경로저장까지변수(@{download_ftp_path})","inputList":[{"types":"Any","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"ftp_instance","title":"FTP연결객체","name":"ftp_instance","tip":"실행다운로드파일/폴더의FTP서비스서버연결객체","value":[{"type":"str","value":""}],"required":true},{"types":"FileType","formType":{"type":"RADIO"},"key":"file_type","title":"다운로드객체","name":"file_type","tip":"","options":[{"label":"파일","value":"file"},{"label":"폴더","value":"folder"}],"default":"file","required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"download_file_name","title":"대기다운로드파일","name":"download_file_name","tip":"지원단일개또는다중개파일다운로드,다중개파일이름사용열기,예:test1.txt,test2.txt,test3.txt","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.download_file_name.show","expression":"return $this.file_type.value == ''file''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"download_folder_name","title":"대기다운로드폴더","name":"download_folder_name","tip":"지원단일개또는다중개폴더다운로드,다중개폴더사용열기,예:folder1,folder2,folder3","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.download_folder_name.show","expression":"return $this.file_type.value == ''folder''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"dst_path","title":"다운로드","name":"dst_path","tip":"본저장경로","default":"","required":true},{"types":"StateType","formType":{"type":"RADIO"},"key":"state_type","title":"저장 경로가 없을 때","name":"state_type","tip":"저장 경로가 없을 때 실행할 동작","options":[{"label":"생성","value":"create"},{"label":"오류 처리","value":"error"}],"default":