INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('240','Network.http_download','{"key":"Network.http_download","title":"HTTP 다운로드","version":"1.0.1","src":"astronverse.network.network.Network().http_download","comment":"URL(@{url})의 파일을 @{dst_dir}에 다운로드하고 경로를 @{http_download_path}에 저장합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"url","title":"URL","name":"url","tip":"다운로드할 파일의 URL을 입력합니다.","default":"","value":[{"type":"str","value":""}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"dst_dir","title":"저장 폴더","name":"dst_dir","tip":"파일을 저장할 폴더를 선택합니다.","default":"","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"rename","title":"저장 파일명","name":"rename","tip":"비워두면 URL의 파일명을 사용합니다.","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.rename.show","expression":"return $this.state_type.value == ''create''"}],"required":false},{"types":"StateType","formType":{"type":"RADIO"},"key":"state_type","title":"디렉터리가 없을 때","name":"state_type","tip":"파일 저장 디렉터리가 없을 때 처리 방식","options":[{"label":"생성","value":"create"},{"label":"오류 처리","value":"error"}],"default":"create","required":false},{"types":"FileExistenceType","formType":{"type":"SELECT"},"key":"exist_type","title":"파일명 충돌 처리 방식","name":"exist_type","tip":"저장 폴더에 같은 이름의 파일이 있을 때 처리 방식을 선택합니다.","options":[{"label":"새 이름으로 저장","value":"rename"},{"label":"덮어쓰기","value":"overwrite"},{"label":"건너뛰기","value":"cancel"}],"default":"rename","required":false}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"http_download_path","title":"다운로드 파일 경로","tip":"다운로드된 파일 경로를 저장합니다."}],"icon":"http-download","helpManual":"지정한 URL의 파일을 다운로드합니다."}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('241','Network.http_request','{"key":"Network.http_request","title":"HTTP 요청","version":"1.0.1","src":"astronverse.network.network.Network().http_request","comment":"URL(@{url})로 HTTP @{request_type} 요청을 보내고 결과를 @{http_response}에 저장합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"url","title":"URL","name":"url","tip":"","default":"","value":[{"type":"str","value":""}],"required":true},{"types":"RequestType","formType":{"type":"SELECT"},"key":"request_type","title":"요청 방식","name":"request_type","tip":"","options":[{"label":"post","value":"post"},{"label":"속성 가져오기","value":"get"},{"label":"connect","value":"connect"},{"label":"put","value":"put"},{"label":"patch","value":"patch"},{"label":"delete","value":"delete"},{"label":"options","value":"options"},{"label":"head","value":"head"},{"label":"trace","value":"trace"}],"default":"post","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"headers","title":"요청 헤더","name":"headers","tip":"JSON 형식으로 요청 헤더를 입력합니다.","default":"","value":[{"type":"str","value":""}],"required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"body","title":"요청 본문","name":"body","tip":"POST, PUT, PATCH 요청에 보낼 본문을 입력합니다.","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.body.show","expression":"return [''post'', ''put''].includes($this.request_type.value)"}],"required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"file"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"POST 요청에 함께 보낼 파일 정보를 JSON 형식으로 입력합니다.","default":"","dynamics":[{"key":"$this.file_path.show","expression":"return $this.request_type.value == ''post''"}],"required":false},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"time_out","title":"시간 초과(초)","name":"time_out","tip":