INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('265','StringProcess.cut_string_to_length','{"key":"StringProcess.cut_string_to_length","title":"텍스트 일부 가져오기","version":"1.0.2","src":"astronverse.dataprocess.string.StringProcess().cut_string_to_length","comment":"텍스트 @{string_data}에서 @{cut_type} 방식으로 @{length} 길이만큼 잘라 @{cut_string}에 저장합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"string_data","title":"대상 텍스트","name":"string_data","tip":"","value":[{"type":"str","value":""}],"required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"length","title":"가져올 길이","name":"length","tip":"","value":[{"type":"str","value":""}],"required":true},{"types":"CutStringType","formType":{"type":"RADIO"},"key":"cut_type","title":"조회 유형","name":"cut_type","tip":"","options":[{"label":"에서일개문자열기 가져오기","value":"first"},{"label":"지정 위치부터 가져오기","value":"index"},{"label":"에서지정문자열열기 가져오기","value":"string"}],"default":"first","required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"index","title":"에서개문자열기 가져오기","name":"index","tip":"","default":0,"value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.index.show","expression":"return $this.cut_type.value == ''index''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"find_str","title":"필요검색의문자열","name":"find_str","tip":"","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.find_str.show","expression":"return $this.cut_type.value == ''string''"}],"required":true}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"cut_string","title":"추출 결과 텍스트","tip":""}],"icon":"screenshot-fixed-text","helpManual":""}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
