INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('274','System.compress','{"key":"System.compress","title":"압축하기","version":"1.0.1","src":"astronverse.system.compress.Compress().compress","comment":"압축 @{file_type} 까지지정디렉터리 @{compress_dir} 중, 저장압축패키지경로  @{compress_path}","inputList":[{"types":"FileFolderType","formType":{"type":"RADIO"},"key":"file_type","title":"선택압축방식","name":"file_type","tip":"선택압축파일/폴더/파일 및 폴더","options":[{"label":"파일","value":"file"},{"label":"폴더","value":"folder"},{"label":"파일 및 폴더","value":"both"}],"default":"file","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"files"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"선택또는입력대기압축파일 경로","default":"","dynamics":[{"key":"$this.file_path.show","expression":"return $this.file_type.value != ''folder''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"folder_path","title":"대기압축폴더","name":"folder_path","tip":"선택또는입력대기압축폴더 경로","default":"","dynamics":[{"key":"$this.folder_path.show","expression":"return $this.file_type.value != ''file''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"compress_dir","title":"목록경로","name":"compress_dir","tip":"저장목록 압축파일 경로","default":"","required":true},{"types":"StateType","formType":{"type":"RADIO"},"key":"state_type","title":"대상 경로가 없을 때","name":"state_type","tip":"선택한 대상 경로가 없을 때 실행할 동작","options":[{"label":"생성","value":"create"},{"label":"안내오류","value":"error"}],"default":"error","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"compress_name","title":"압축패키지이름","name":"compress_name","tip":"지정압축패키지이름, 비워 두면이면으로압축목록중일개압축파일이름명령이름","default":"","required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"pwd"