INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('275','System.copy_clip','{"key":"System.copy_clip","title":"클립보드에 복사","version":"1.0.1","src":"astronverse.system.clipboard.Clipboard().copy_clip","comment":"를 @{content_type}  @{message||file_path||folder_path} 클립보드에 복사","inputList":[{"types":"ContentType","formType":{"type":"SELECT"},"key":"content_type","title":"복사유형","name":"content_type","tip":"선택복사까지의내용유형","options":[{"label":"텍스트 내용","value":"msg"},{"label":"HTML형식텍스트 내용","value":"html"},{"label":"파일","value":"file"},{"label":"폴더","value":"folder"}],"default":"msg","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"message","title":"대기복사의텍스트 내용","name":"message","tip":"입력텍스트 내용","default":"","dynamics":[{"key":"$this.message.show","expression":"return $this.content_type.value == ''msg''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"file"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"입력또는선택대기복사파일","default":"","dynamics":[{"key":"$this.file_path.show","expression":"return $this.content_type.value == ''file''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"folder_path","title":"대기복사의폴더 경로","name":"folder_path","tip":"입력또는선택대기복사폴더","default":"","dynamics":[{"key":"$this.folder_path.show","expression":"return $this.content_type.value == ''folder''"}],"required":true}],"outputList":[],"icon":"copy-to-clipboard","helpManual":"지원를텍스트 내용/파일/폴더클립보드에 복사"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('276','System.get_pid','{"key":"System.get_pid","title":"PID 가져오기","version":"1.0.1","src":"astronverse.system.process.Process().get_pid","comment":"입력한 @{process_name}과 일치하는 PID를 찾아 @{match_proces_pid}에 저장합니다.","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"process_name","title":"대기매칭내용","name":"process_name","tip":"입력대기매칭내용, 매칭방식아래입력할이름, 분크기","default":"","required":true},{"types":"SearchType","formType":{"type":"RADIO"},"key":"search_type","title":"매칭방식","name":"search_type","tip":"선택매칭방식","options":[{"label":"매칭","value":"exact"},{"label":"매칭","value":"fuzzy"},{"label":"정상이면테이블방식매칭","value":"regex"}],"default":"exact","required":false},{"types":"PidType","formType":{"type":"RADIO"},"key":"pid_type","title":"조회 내용","name":"pid_type","tip":"가져올 PID 매칭 범위를 지정합니다.","options":[{"label":"전체","value":"all"},{"label":"단일","value":"one"}],"default":"all","required":false}],"outputList":[{"types":"Any","formType":{"type":"RESULT"},"key":"match_proces_pid","title":"PID 목록","tip":"전체 매칭 PID는 목록으로, 단일 매칭 PID는 단일 값으로 출력합니다."}],"icon":"get-process-pid","helpManual":"프로세스 이름을 입력해 PID를 조회합니다. 단일 PID 또는 전체 매칭 PID 목록을 출력할 수 있습니다."}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('277','System.paste_clip','{"key":"System.paste_clip","title":"클립보드 가져오기","version":"1.0.1","src":"astronverse.system.clipboard.Clipboard().paste_clip","comment":"클립보드에서 @{content_type} 내용을 가져와 @{output_content}에 저장합니다.","inputList":[{"types":"ContentType","formType":{"type":"SELECT"},"key":"content_type","title":"가져올 유형","name":"content_type","tip":"클립보드에서 가져올 내용 유형을 선택합니다.","options":[{"label":"텍스트","value":"msg"},{"label":"HTML 텍스트","value":"html"},{"label":"파일","value":"file"},{"label":"폴더","value":"folder"}],"default":"msg","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"dst_path","title":"저장 경로","name":"dst_path","tip":"파일 또는 폴더를 저장할 경로를 선택하거나 입력합니다.","default":"","dynamics":[{"key":"$this.dst_path.show","expression":"return [''file'', ''folder''].includes($this.content_type.value)"}],"required":true},{"types":"StateType","formType":{"type":"RADIO"},"key":"state_type","title":"저장 경로가 없을 때","name":"state_type","tip":"저장 경로가 없을 때 실행할 동작","options":[{"label":"생성","value":"create"},{"label":"오류 표시","value":"error"}],"default":"error","dynamics":[{"key":"$this.state_type.show","expression":"return [''folder'', ''file''].includes($this.content_type.value)"}],"required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"dst_file_name","title":"저장 파일명","name":"dst_file_name","tip":"비워 두면 기존 파일 이름을 사용합니다.","default":"","dynamics":[{"key":"$this.dst_file_name.show","expression":"return $this.content_type.value == ''file''"}],"required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"dst_folder_name","title":"저장 폴더명","name":"dst_folder_name","tip":"비워 두면 기존 폴더 이름을 사용합니다.","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.dst_folder_name.show","expression":"return $this.content_type.value == ''folder''"}],"requir