INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('278','System.printer','{"key":"System.printer","title":"프린터 작업","version":"1.0.1","src":"astronverse.system.system.System().printer","comment":"사용프린터 @{printer_name} 인쇄지정파일 @{file_path||folder_path} , 실행 결과출력변수 @{printer_status}","inputList":[{"types":"FileType","formType":{"type":"SELECT"},"key":"file_type","title":"인쇄객체","name":"file_type","tip":"지정인쇄객체, 지원인쇄Word, Excel, PDF및이미지파일, 또는량인쇄폴더중국어파일","options":[{"label":"PDF 문서","value":"pdf"},{"label":"Word 문서","value":"word"},{"label":"Excel 문서","value":"excel"},{"label":"이미지","value":"picture"}],"default":"pdf","required":true},{"types":"DocAppType","formType":{"type":"RADIO"},"key":"doc_app_type","title":"Word문서사용","name":"doc_app_type","tip":"Word 열기문서선택의사용","options":[{"label":"Word","value":"Word"},{"label":"WPS","value":"WPS"},{"label":"프로그램","value":"Default"}],"default":"Default","dynamics":[{"key":"$this.doc_app_type.show","expression":"return $this.file_type.value == ''word''"}],"required":true},{"types":"XlsAppType","formType":{"type":"RADIO"},"key":"xls_app_type","title":"Excel문서사용","name":"xls_app_type","tip":"Excel 열기문서선택의사용","options":[{"label":"Excel","value":"Excel"},{"label":"WPS","value":"WPS"},{"label":"프로그램","value":"Default"}],"default":"Default","dynamics":[{"key":"$this.xls_app_type.show","expression":"return $this.file_type.value == ''excel''"}],"required":true},{"types":"BatchType","formType":{"type":"RADIO"},"key":"batch_print","title":"인쇄방식","name":"batch_print","tip":"인쇄방식, 량인쇄지원폴더아래의파일, 지원하지 않음폴더아래폴더의파일","options":[{"label":"량인쇄","value":"batch"},{"label":"단일 요소 객체","value":"single"}],"default":"single","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"file"}},"key":"file_path","title":"파일 경로","name":"file_path","tip":"선택또는입력대기인쇄파일 경로","default":"","dynamics":[{"key":"$this.file_path.show","expression":"return $this.batch_print.value == ''single''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"filters":[],"file_type":"folder"}},"key":"folder_path","title":"대기인쇄파일 디렉터리","name":"folder_path","tip":"인쇄할 파일 또는 폴더 경로를 선택하거나 입력합니다. 폴더를 선택하면 해당 폴더의 지원 파일을 인쇄합니다.","default":"","dynamics":[{"key":"$this.folder_path.show","expression":"return $this.batch_print.value == ''batch''"}],"required":true},{"types":"PrinterType","formType":{"type":"RADIO"},"key":"printer_type","title":"인쇄","name":"printer_type","tip":"인쇄닫기매개변수","options":[{"label":"지정","value":"custom"},{"value":"default","label":null}],"default":"default","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"printer_name","title":"프린터이름","name":"printer_name","tip":"입력프린터이름, 비워 두면시사용프린터","default":"","value":[{"type":"str","value":""}],"required":false},{"types":"PaperType","formType":{"type":"SELECT"},"key":"paper_size","name":"paper_size","tip":"지정인쇄","options":[{"label":"A3","value":"A3"},{"label":"A4","value":"A4"},{"label":"LA4","value":"LA4"},{"label":"A5","value":"A5"},{"label":"B4","value":"B4"},{"label":"B5","value":"B5"},{"label":"C_SHEET","value":"C_SHEET"},{"label":"D_SHEET","value":"D_SHEET"},{"value":"CUSTOM","label":null}],"default":"A4","dynamics":[{"key":"$this.paper_size.show","expression":"return $this.printer_type.value == ''custom''"}],"required":true,"title":null},{"types":"Float","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"page_weight","title":"너비정도","name":"page_weight","tip":"입력인쇄너비정도","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.page_weight.show","expression":"return $this.paper_size.value == ''CUSTOM'' && $this.printer_type.value == ''custom''"}],"required":true},{"types":"Float","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"page_height","title":"높이정도","name":"page_height","tip":"입력인쇄높이정도","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.page_height.show","exp