INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('680','DataTable.copy_data','{"key":"DataTable.copy_data","title":"데이터 테이블 복사","version":"1.0.3","src":"astronverse.datatable.datatable.DataTable().copy_data","comment":"데이터 테이블 복사중의 @{copy_type} 데이터까지잘라내기","inputList":[{"types":"BaseOperateType","formType":{"type":"SELECT"},"key":"copy_type","title":"복사방식","name":"copy_type","tip":"선택복사데이터의방식(셀, 행, 열, )","options":[{"label":"셀","value":"cell"},{"label":"행 기준 출력","value":"row"},{"label":"열 기준 출력","value":"column"},{"label":"영역","value":"area"}],"default":"cell","required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"row","title":"행","name":"row","tip":"지정할복사의행(예1, 2, 3...)","default":1,"value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.row.show","expression":"return [''row'', ''cell''].includes($this.copy_type.value)"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"col","title":"열","name":"col","tip":"지정할복사의열(예A, B, C, AB...)","default":"A","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.col.show","expression":"return [''column'', ''cell''].includes($this.copy_type.value)"}],"required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"start_row","title":"시작 행","name":"start_row","tip":"지정할복사의시작 행(예1, 2, 3...)","default":1,"value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.start_row.show","expression":"return $this.copy_type.value == ''area''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"start_col","title":"시작 열","name":"start_col","tip":"지정할복사의시작 열(예A, B, C, AB...)","default":"A","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.start_col.show","expression":"return $this.copy_type.value == ''area''"}],"required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"end_row","title":"끝 행","name":"end_row","tip":"끝 행은 시작 행보다 커야 합니다. 0 또는 비워 두면 마지막 행까지 가져옵니다.","default":0,"value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.end_row.show","expression":"return $this.copy_type.value == ''area''"}],"required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"end_col","title":"끝 열","name":"end_col","tip":"끝 열은 시작 열보다 뒤에 있어야 합니다. 비워 두면 마지막 열까지 가져옵니다.","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.end_col.show","expression":"return $this.copy_type.value == ''area''"}],"required":false}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"copied_cell","title":"복사의셀","tip":"으로문자열방식반환복사의셀데이터","dynamics":[{"key":"$this.copied_cell.show","expression":"return $this.copy_type.value == ''cell''"}]},{"types":"List","formType":{"type":"RESULT"},"key":"copied_row","title":"복사의행","tip":"으로배열방식반환복사의행데이터","dynamics":[{"key":"$this.copied_row.show","expression":"return $this.copy_type.value == ''row''"}]},{"types":"List","formType":{"type":"RESULT"},"key":"copied_column","title":"복사의열","tip":"으로배열방식반환복사의열데이터","dynamics":[{"key":"$this.copied_column.show","expression":"return $this.copy_type.value == ''column''"}]},{"types":"List","formType":{"type":"RESULT"},"key":"copied_area","title":"복사의","tip":"으로이배열방식반환복사의데이터","dynamics":[{"key":"$this.copied_area.show","expression":"return $this.copy_type.value == ''area''"}]}],"icon":"copy_data_table","helpManual":""}',NULL,'2026-01-27 17:17:49','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('681','DataTable.delete_data','{"key":"DataTable.delete_data","title":"데이터 테이블 삭제","version":"1.0.3","src":"astronverse.datatable.datatable.DataTable().delete_data","comment":"데이터 테이블 삭제중 @{delete_type} 의데이터","inputList":[{"types":"BaseOperateType","formType":{"type":"SELECT"},"key":"delete_type","title":"삭제방식","name":"delete_type","tip":"선택삭제데이터의방식(셀, 행, 열, )","options":[{"label":"셀","value":"cell"},{"label":"행 기준 출력","value":"row"},{"label":"열 기준 출력","value":"column"},{"label":"영역","value":"area"}],"default":"cell","required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"row","title":"행","name":"row","tip":"지정할삭제의행(예1, 2, 3...)","default":1,"value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.row.show","expression":"return [''cell'', ''row''].includes($this.delete_type.value)"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"col","title":"열","name":"col","tip":"지정할삭제의열(예A, B, C, AB...)","default":"A","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.col.show","expression":"return [''cell'', ''column''].includes($this.delete_type.value)"}],"required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"start_row","title":"시작 행","name":"start_row","tip":"지정할삭제의시작 행(예1, 2, 3...)","default":1,"value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.start_row.show","expression":"return $this.delete_type.value == ''area''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"start_col","title":"시작 열","name":"start_col","tip":"지정할삭제의시작 열(예A, B, C, AB...)","default":"A","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.start_col.show","expression":"return $this.delete_type.value == ''area''"}],"required":true},{"types":"int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"end_row","title":"끝 행","name":"end_row","tip":"끝 행은 시작 행보다 커야 합니다. 0 또는 비워 두면 마지막 행까지 가져옵니다.","default":0,"value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.end_row.show","expression":"return $this.delete_type.value == ''area''"}],"required":false},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"end_col","title":"끝 열","name":"end_col","tip":"끝 열은 시작 열보다 뒤에 있어야 합니다. 비워 두면 마지막 열까지 가져옵니다.","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.end_col.show","expression":"return $this.delete_type.value == ''area''"}],"required":false},{"types":"DeleteCellMove","formType":{"type":"RADIO"},"key":"delete_cell_move","title":"셀삭제후방식","name":"delete_cell_move","tip":"삭제셀시의방식(왼쪽, 위)","options":[{"label":"셀왼쪽","value":"left"},{"label":"셀위","value":"up"},{"label":"셀아니오","value":"not"}],"default":"up","dynamics":[{"key":"$this.delete_cell_move.show","expression":"return $this.delete_type.value == ''cell''"}],"required":true},{"types":"Bool","formType":{"type":"SWITCH","params":{}},"key":"delete_col_move","title":"열삭제여부","name":"delete_col_move","tip":"삭제열시의방식(왼쪽)","options":[{"label":"예","value":true},{"label":"아니오","value":false}],"default":true,"dynamics":[{"key":"$this.delete_col_move.show","expression":"return $this.delete_type.value == ''column''"}],"required":true},{"types":"Bool","formType":{"type":"SWITCH","params":{}},"key":"delete_row_move","title":"행삭제여부","name":"delete_row_move","tip":"삭제행시의방식(위)","options":[{"label":"예","value":true},{"label":"아니오","value":false}],"default":true,"dynamics":[{"key":"$this.delete_row_move.show","expression":"return $this.delete_type.value == ''row''"}],"required":true}],"outputList":[],"icon":"delete_data_table","helpManual":""}',NULL,'2026-01-27 17:17:49','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('682','DataTable.export_data_table_to_file','{"key":"DataTable.export_data_table_to_file","title":"데이터 테이블을 파일로 내보내기","version":"1.0.3","src":"astronverse.datatable.datatable.DataTable().export_data_table_to_file","comment":"를데이터테이블내보내기까지파일 @{export_dest_path}","inputList":[{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON_FILE","params":{"file_type":"folder"}},"key":"export_dest_path","title":"내보내기목록경로","name":"export_dest_path","tip":"내보내기파일의저장경로","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"export_file_name","title":"내보내기파일이름","name":"export_file_name","tip":"내보내기의파일이름","default":"data_table","value":[{"type":"str","value":""}],"required":false},{"types":"ExportFileType","formType":{"type":"SELECT"},"key":"export_file_type","title":"내보내기파일유형","name":"export_file_type","tip":"선택내보내기의파일유형","options":[{"label":".xlsx파일","value":"xlsx"},{"label":".xls파일","value":"xls"},{"label":".csv파일","value":"csv"},{"label":".json파일","value":"json"}],"default":"xlsx","required":true},{"types":"Bool","formType":{"type":"SWITCH","params":{}},"key":"is_overwrite","title":"여부덮어쓰기이름파일","name":"is_overwrite","tip":"결과가저장된 이름파일, 여부덮어쓰기해당파일, 아니오이면이름 변경","options":[{"label":"예","value":true},{"label":"아니오","value":false}],"default":true,"required":true}],"outputList":[{"types":"Str","formType":{"type":"RESULT"},"key":"export_file_path","title":"내보내기파일 경로","tip":"반환내보내기파일의경로"}],"icon":"export_data_table","helpManual":""}',NULL,'2026-01-27 17:17:49','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('683','DataTable.filter_data_table','{"key":"DataTable.filter_data_table","title":"데이터 테이블 필터","version":"1.0.3","src":"astronverse.datatable.datatable.DataTable().filter_data_table","comment":"근거 @{filter_type} 파일선택데이터테이블","inputList":[{"types":"FilterType","formType":{"type":"SELECT"},"key":"filter_type","title":"선택유형","name":"filter_type","tip":"선택선택유형(열선택, 행선택, 테이블선택)","options":[{"label":"행 기준 출력","value":"row"},{"label":"열 기준 출력","value":"column"},{"label":"테이블선택","value":"table"}],"default":"column","required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"row","title":"행","name":"row","tip":"지정할선택의행","default":1,"value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.row.show","expression":"return $this.filter_type.value == ''row''"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"col","title":"열","name":"col","tip":"지정할선택의열","default":"A","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.col.show","expression":"return $this.filter_type.value == ''column''"}],"required":true},{"types":"ConditionType","formType":{"type":"SELECT"},"key":"condition_type","title":"파일유형","name":"condition_type","tip":"선택파일유형","options":[{"label":"대기","value":"equals"},{"label":"아니오대기","value":"not_equals"},{"label":"대","value":"greater_than"},{"label":"소","value":"less_than"},{"label":"대대기","value":"greater_than_or_equal"},{"label":"소대기","value":"less_than_or_equal"},{"label":"패키지","value":"contains"},{"label":"아니오패키지","value":"not_contains"},{"label":"빈 값","value":"is_empty"},{"label":"빈 값 아님","value":"is_not_empty"},{"label":"열기 예","value":"starts_with"},{"label":"결과예","value":"ends_with"},{"label":"에서날짜전","value":"date_before"},{"label":"에서날짜후","value":"date_after"},{"label":"에서날짜","value":"date_between"}],"default":"equals","required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"condition_value","title":"파일값","name":"condition_value","tip":"입력파일값","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.condition_value.show","expression":"return ![''date_after'', ''date_before'', ''date_between''].includes($this.condition_type.value)"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"date_value","title":"날짜값","name":"date_value","tip":"선택날짜값","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.date_value.show","expression":"return [''date_after'', ''date_before''].includes($this.condition_type.value)"}],"required":true},{"types":"Str","formType":{"type":"INPUT_VARIABLE_PYTHON"},"key":"date_range","title":"날짜","name":"date_range","tip":"선택날짜","default":"","value":[{"type":"str","value":""}],"dynamics":[{"key":"$this.date_range.show","expression":"return $this.condition_type.value == ''date_between''"}],"required":true},{"types":"Bool","formType":{"type":"SWITCH","params":{}},"key":"is_case_sensitive","title":"분크기","name":"is_case_sensitive","tip":"시간대 선택여부분크기","options":[{"label":"예","value":true},{"label":"아니오","value":false}],"default":true,"dynamics":[{"key":"$this.is_case_sensitive.show","expression":"return [''equals'', ''not_equals'', ''contains'', ''not_contains'', ''starts_with'', ''ends_with''].includes($this.condition_type.value)"}],"required":true},{"types":"Bool","formType":{"type":"SWITCH","params":{}},"key":"is_save_filtered","title":"저장선택결과","name":"is_save_filtered","tip":"여부저장선택결과","options":[{"label":"예","value":true},{"label":"아니오","value":false}],"default":false,"required":true}],"outputList":[{"types":"List","formType":{"type":"RESULT"},"key":"data_filtered","title":"선택결과","tip":"반환선택후의데이터결과"}],"icon":"filter_data_table","helpManual":""}',NULL,'2026-01-27 17:17:49','2026-02-24 17:09:16');
