INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('706','Gui.mouse_move_new','{"key":"Gui.mouse_move_new","title":"마우스 이동","version":"1.0.1","src":"astronverse.input.gui_mouse.GuiMouse().mouse_move_new","comment":"@{window_type} 기준 좌표(@{position_x}, @{position_y})로 마우스를 이동합니다.","inputList":[{"types":"WindowType","formType":{"type":"RADIO"},"key":"window_type","title":"창유형","name":"window_type","tip":"전체 화면은 화면 왼쪽 위를 기준으로, 창은 창 왼쪽 위를 기준으로 위치를 계산합니다.","options":[{"label":"개화면","value":"fullscreen"},{"label":"창","value":"active_window"}],"default":"fullscreen","required":true},{"types":"WinPick","formType":{"type":"PICK","params":{"use":"WINDOW"}},"key":"window_pick","title":"창선택","name":"window_pick","tip":"기준으로 사용할 창을 선택합니다.","dynamics":[{"key":"$this.window_pick.show","expression":"return $this.window_type.value == ''active_window''"}],"required":true,"noInput":true},{"types":"Str","formType":{"type":"MOUSEPOSITION","params":{"size":"middle"}},"key":"get_mouse_position","title":"마우스 위치 가져오기","name":"get_mouse_position","tip":"이동 후 현재 마우스 위치를 반환할지 선택합니다.","default":"","dynamics":[{"key":"$this.get_mouse_position.show","expression":"return $this.window_type.value == ''fullscreen''"}],"required":false},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON","params":{"size":"middle"}},"key":"position_x","title":"X 좌표","name":"position_x","tip":"이동할 가로 좌표를 입력합니다.","default":0,"required":true},{"types":"Int","formType":{"type":"INPUT_VARIABLE_PYTHON","params":{"size":"middle"}},"key":"position_y","title":"Y 좌표","name":"position_y","tip":"이동할 세로 좌표를 입력합니다.","default":0,"required":true},{"types":"MoveType","formType":{"type":"RADIO"},"key":"move_type","title":"마우스 이동 방식","name":"move_type","tip":"즉시 이동 또는 부드러운 이동 방식을 선택합니다.","options":[{"label":"직선","value":"linear"},{"label":"자연스러운 이동","value":"simulation"},{"label":"즉시 이동","value":"teleportation"}],"default":"linear","required":true},{"types":"Speed","formType":{"type":"RADIO"},"key":"move_speed","title":"마우스 속도","name":"move_speed","tip":"부드럽게 이동할 때 사용할 이동 속도를 선택합니다.","options":[{"label":"느림","value":"slow"},{"label":"보통","value":"normal"},{"label":"빠름","value":"fast"}],"default":"normal","level":"advanced","dynamics":[{"key":"$this.move_speed.show","expression":"return [''linear'', ''simulation''].includes($this.move_type.value)"}],"required":true}],"outputList":[],"icon":"mouse-move","helpManual":""}',NULL,'2026-02-02 14:31:26','2026-02-24 17:09:16');
